<?php namespace App\Repositories\Attendance;use App\Repositories\BaseRepository;use App\Models\Attendance\AttendanceSetting;use Illuminate\Database\Eloquent\Collection;class AttendanceSettingRepository extends BaseRepository{    public function __construct(AttendanceSetting $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByAcademicYear(int $academicYearId): ?AttendanceSetting    {        return $this->query()->where('academic_year_id', $academicYearId)->first();    }    public function getByClass(int $classId): ?AttendanceSetting    {        return $this->query()->where('class_id', $classId)->first();    }    public function getDefaultSetting(): ?AttendanceSetting    {        return $this->query()->where('is_default', true)->first();    }    public function updateSetting(int $id, array $data): AttendanceSetting    {        return $this->update($id, $data);    }    public function createOrUpdate(array $criteria, array $data): AttendanceSetting    {        $setting = $this->query()->where($criteria)->first();        if ($setting) {            $this->update($setting->id, $data);            return $setting->fresh();        }        return $this->create(array_merge($criteria, $data));    }}